'use client';
import { useState, useEffect, useCallback, useRef, Suspense } from 'react';
import { useSearchParams } from 'next/navigation';
import { getMenu, addOrder, getOrders, addWaiterCall, MenuItem, Order, OrderItem } from '@/lib/storage';

const CATEGORIES   = ['All', 'Biryani', 'Starters', 'Mains', 'Breads', 'Desserts', 'Drinks'];
const BADGE_LABELS: Record<string, string> = {
  bestseller: '⭐ Bestseller', popular: '🔥 Popular',
  chef: "👨‍🍳 Chef's Special", famous: '🏆 Famous', new: '✨ New',
};
const STATUS_LABEL: Record<string, { label: string; color: string; icon: string }> = {
  pending:   { label: 'Order Received',  color: '#f59e0b', icon: '📋' },
  preparing: { label: 'Being Prepared',  color: '#3b82f6', icon: '👨‍🍳' },
  prepared:  { label: 'Ready to Serve',  color: '#8b5cf6', icon: '✅' },
  served:    { label: 'Served',          color: '#06b6d4', icon: '🍽️' },
  completed: { label: 'Completed',       color: '#16a34a', icon: '🎉' },
  cancelled: { label: 'Cancelled',       color: '#ef4444', icon: '❌' },
};

const FLOW = ['pending', 'preparing', 'prepared', 'served', 'completed'];
const MAX_QTY = 20;

function TrackingBar({ status }: { status: string }) {
  const steps = ['pending', 'preparing', 'prepared', 'served', 'completed'];
  const cur = steps.indexOf(status);
  if (status === 'cancelled') return (
    <div style={{ background: '#fef2f2', borderRadius: '10px', padding: '0.6rem 1rem', fontSize: '0.82rem', color: '#dc2626', fontWeight: 700 }}>
      ❌ Order has been cancelled
    </div>
  );
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '0.25rem', marginTop: '0.5rem' }}>
      {steps.map((step, i) => {
        const done   = i < cur;
        const active = i === cur;
        const info   = STATUS_LABEL[step];
        return (
          <div key={step} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.2rem' }}>
            <div style={{
              width: '28px', height: '28px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.75rem', fontWeight: 900, transition: 'all 0.3s',
              background: done ? '#16a34a' : active ? info.color : '#e5e7eb',
              color: done || active ? 'white' : '#9ca3af',
              boxShadow: active ? `0 0 0 3px ${info.color}33` : 'none',
            }}>
              {done ? '✓' : info.icon}
            </div>
          </div>
        );
      })}
    </div>
  );
}

type View = 'menu' | 'tracking' | 'receipt';

function TableContent() {
  const params  = useSearchParams();
  const tableId = parseInt(params.get('table') || '1');

  const [menu, setMenu]                 = useState<MenuItem[]>([]);
  const [cart, setCart]                 = useState<{ item: MenuItem; qty: number }[]>([]);
  const [filter, setFilter]             = useState('All');
  const [cartOpen, setCartOpen]         = useState(false);
  const [name, setName]                 = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [view, setView]                       = useState<View>('menu');
  const [activeOrderId, setActiveOrderId]     = useState<string | null>(null);
  const [activeOrder, setActiveOrder]         = useState<Order | null>(null);
  const [allOrders, setAllOrders]             = useState<Order[]>([]);

  // Call waiter
  const [callSent, setCallSent]         = useState(false);
  const [callCooldown, setCallCooldown] = useState(false);

  // Prevents double-submit
  const submittingRef = useRef(false);

  // ── Data refresh ─────────────────────────────────────────────────────────────
  const refreshOrders = useCallback(() => {
    const orders = getOrders();
    setAllOrders(orders);
    if (activeOrderId) {
      const found = orders.find(o => o.id === activeOrderId);
      if (found) setActiveOrder(found);
    }
  }, [activeOrderId]);

  useEffect(() => {
    setMenu(getMenu());
    refreshOrders();
  }, [refreshOrders]);

  // Poll for updates every 4 seconds when tracking
  useEffect(() => {
    if (view === 'tracking' || view === 'receipt') {
      const t = setInterval(refreshOrders, 4000);
      return () => clearInterval(t);
    }
  }, [view, refreshOrders]);

  // Auto-switch to completed receipt
  useEffect(() => {
    if (activeOrder?.status === 'completed' && view === 'tracking') {
      setView('receipt');
    }
  }, [activeOrder, view]);

  // Escape to close cart / checkout (but not when submitting)
  useEffect(() => {
    function handleKey(e: KeyboardEvent) {
      if (e.key !== 'Escape' || isSubmitting) return;
      if (showCheckout) { setShowCheckout(false); return; }
      if (cartOpen) { setCartOpen(false); return; }
    }
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [isSubmitting, showCheckout, cartOpen]);

  // ── Derived data ─────────────────────────────────────────────────────────────
  const filtered  = filter === 'All'
    ? menu.filter(m => m.available !== false)
    : menu.filter(m => m.category === filter && m.available !== false);
  const cartTotal = cart.reduce((s, c) => s + c.item.price * c.qty, 0);
  const cartCount = cart.reduce((s, c) => s + c.qty, 0);

  // Table's recent dine-in orders (for the "in progress" banner)
  const tableOrders = allOrders
    .filter(o => o.tableId === tableId && o.type === 'dine-in')
    .slice(-5)
    .reverse();
  const inProgressOrder = tableOrders.find(o =>
    ['pending','preparing','prepared','served'].includes(o.status),
  );

  // ── Cart helpers ─────────────────────────────────────────────────────────────
  function addToCart(item: MenuItem) {
    setCart(prev => {
      const ex = prev.find(c => c.item.id === item.id);
      if (ex) {
        if (ex.qty >= MAX_QTY) return prev;
        return prev.map(c => c.item.id === item.id ? { ...c, qty: c.qty + 1 } : c);
      }
      return [...prev, { item, qty: 1 }];
    });
  }

  function changeQty(id: number, delta: number) {
    setCart(prev =>
      prev
        .map(c => c.item.id === id ? { ...c, qty: Math.min(c.qty + delta, MAX_QTY) } : c)
        .filter(c => c.qty > 0),
    );
  }

  // ── Place order ───────────────────────────────────────────────────────────────
  function placeOrder() {
    if (submittingRef.current || isSubmitting) return;
    if (!name.trim()) { alert('Enter your name'); return; }
    if (!cart.length) { alert('Cart is empty'); return; }

    submittingRef.current = true;
    setIsSubmitting(true);

    try {
      const ts   = new Date().toISOString();
      const id   = `ORD-${Date.now()}-${Math.random().toString(36).slice(2, 6).toUpperCase()}`;
      const items: OrderItem[] = cart.map(c => ({
        id: c.item.id, name: c.item.name, category: c.item.category,
        price: c.item.price, qty: c.qty, subtotal: c.item.price * c.qty,
      }));
      const order: Order = {
        id, type: 'dine-in', tableId, customerName: name.trim(), items,
        subtotal: cartTotal, discount: 0, total: cartTotal, payment: 'cod',
        status: 'pending',
        timeline: [{ status: 'pending', timestamp: ts }],
        timestamp: ts,
      };
      addOrder(order);
      setActiveOrderId(id);
      setActiveOrder(order);
      setCart([]);
      setShowCheckout(false);
      setView('tracking');
    } finally {
      submittingRef.current = false;
      setIsSubmitting(false);
    }
  }

  // ── Call waiter ───────────────────────────────────────────────────────────────
  function callWaiter(message = 'Assistance needed') {
    if (callCooldown) return;
    addWaiterCall(tableId, message, name || undefined);
    setCallSent(true);
    setCallCooldown(true);
    setTimeout(() => setCallSent(false), 4000);
    setTimeout(() => setCallCooldown(false), 30000);
  }

  const inp: React.CSSProperties = {
    width: '100%', padding: '0.6rem 0.75rem',
    border: '2px solid #e5e7eb', borderRadius: '8px',
    fontFamily: 'Poppins,sans-serif', fontSize: '0.9rem',
  };

  // ── TRACKING VIEW ──────────────────────────────────────────────────────────
  if (view === 'tracking' && activeOrder) {
    const info    = STATUS_LABEL[activeOrder.status] || STATUS_LABEL['pending'];
    const stepIdx = FLOW.indexOf(activeOrder.status);

    return (
      <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg,#1A0800,#2D0F00)', color: 'white', fontFamily: 'Poppins,sans-serif', display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '2rem 1rem' }}>
        <div style={{ width: '100%', maxWidth: '440px' }}>
          {/* Header */}
          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
            <div style={{ fontSize: '3rem', marginBottom: '0.5rem' }}>{info.icon}</div>
            <div style={{ fontFamily: "'Playfair Display',serif", fontSize: '1.6rem', fontWeight: 900 }}>Table {tableId}</div>
            <div style={{ color: '#F9A826', fontSize: '0.85rem' }}>Order • {activeOrder.id}</div>
          </div>

          {/* Status card */}
          <div style={{ background: 'rgba(255,255,255,0.08)', borderRadius: '16px', padding: '1.5rem', marginBottom: '1.25rem', border: `2px solid ${info.color}44`, textAlign: 'center' }}>
            <div style={{ fontSize: '1.1rem', fontWeight: 800, color: info.color, marginBottom: '0.5rem' }}>{info.label}</div>
            <TrackingBar status={activeOrder.status} />
            <div style={{ marginTop: '1rem', display: 'flex', justifyContent: 'space-between', fontSize: '0.72rem', color: '#aaa' }}>
              {FLOW.map((step, i) => (
                <div key={step} style={{ textAlign: 'center', flex: 1, color: i <= stepIdx ? 'white' : '#666', fontWeight: i === stepIdx ? 700 : 400, fontSize: '0.65rem' }}>
                  {STATUS_LABEL[step]?.label?.split(' ')[0]}
                </div>
              ))}
            </div>
          </div>

          {/* Items summary */}
          <div style={{ background: 'rgba(255,255,255,0.06)', borderRadius: '12px', padding: '1rem', marginBottom: '1.25rem' }}>
            <div style={{ fontSize: '0.78rem', fontWeight: 700, color: '#F9A826', marginBottom: '0.6rem', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Your Order</div>
            {(activeOrder.items || []).map((item, i) => (
              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.3rem 0', borderBottom: '1px solid rgba(255,255,255,0.06)', fontSize: '0.85rem' }}>
                <span style={{ color: '#ddd' }}>{item.name} <span style={{ color: '#888' }}>×{item.qty}</span></span>
                <span style={{ fontWeight: 700, color: '#F9A826' }}>₹{item.subtotal ?? item.price * item.qty}</span>
              </div>
            ))}
            <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 800, marginTop: '0.6rem', fontSize: '0.95rem' }}>
              <span style={{ color: '#ddd' }}>Total</span>
              <span style={{ color: '#E65C00' }}>₹{activeOrder.total}</span>
            </div>
          </div>

          {/* Timeline */}
          {(activeOrder.timeline || []).length > 0 && (
            <div style={{ background: 'rgba(255,255,255,0.06)', borderRadius: '12px', padding: '1rem', marginBottom: '1.25rem' }}>
              <div style={{ fontSize: '0.78rem', fontWeight: 700, color: '#F9A826', marginBottom: '0.6rem', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Order Timeline</div>
              {activeOrder.timeline.map((ev, i) => (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', padding: '0.3rem 0' }}>
                  <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: STATUS_LABEL[ev.status]?.color || '#888', flexShrink: 0 }} />
                  <span style={{ color: STATUS_LABEL[ev.status]?.color || '#aaa', fontWeight: 700, fontSize: '0.8rem', textTransform: 'capitalize', minWidth: '70px' }}>{ev.status}</span>
                  <span style={{ color: '#888', fontSize: '0.75rem' }}>{new Date(ev.timestamp).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}</span>
                  {ev.by && <span style={{ color: '#666', fontSize: '0.72rem' }}>by {ev.by}</span>}
                </div>
              ))}
            </div>
          )}

          {/* Call waiter + order more */}
          <div style={{ display: 'flex', gap: '0.75rem', marginBottom: '1rem' }}>
            <button
              onClick={() => callWaiter('Customer needs assistance')}
              disabled={callCooldown}
              style={{ flex: 1, padding: '0.75rem', borderRadius: '12px', border: 'none', cursor: callCooldown ? 'not-allowed' : 'pointer', fontWeight: 700, fontFamily: 'Poppins,sans-serif', fontSize: '0.88rem', background: callSent ? '#16a34a' : callCooldown ? '#374151' : '#F9A826', color: callCooldown && !callSent ? '#9ca3af' : '#1A0800', transition: 'all 0.3s' }}
            >
              {callSent ? '✅ Waiter Notified!' : callCooldown ? '⏳ Please wait...' : '🔔 Call Waiter'}
            </button>
            <button
              onClick={() => setView('menu')}
              style={{ flex: 1, padding: '0.75rem', borderRadius: '12px', border: '2px solid rgba(255,255,255,0.2)', background: 'transparent', cursor: 'pointer', fontWeight: 700, fontFamily: 'Poppins,sans-serif', fontSize: '0.88rem', color: 'white' }}
            >
              ➕ Order More
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ── RECEIPT VIEW ────────────────────────────────────────────────────────────
  if (view === 'receipt' && activeOrder) {
    return (
      <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg,#faf8f3,#f5f0e8)', fontFamily: 'Poppins,sans-serif', display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '2rem 1rem' }}>
        <div style={{ width: '100%', maxWidth: '420px' }}>
          <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
            <div style={{ fontSize: '3.5rem', marginBottom: '0.5rem' }}>🎉</div>
            <div style={{ fontFamily: "'Playfair Display',serif", fontSize: '1.5rem', fontWeight: 900, color: '#1A0800' }}>Thank You!</div>
            <div style={{ fontSize: '0.85rem', color: '#888' }}>Hope you enjoyed your meal</div>
          </div>

          {/* Receipt card */}
          <div style={{ background: 'white', borderRadius: '16px', boxShadow: '0 4px 20px rgba(0,0,0,0.1)', overflow: 'hidden', marginBottom: '1rem' }}>
            <div style={{ background: 'linear-gradient(135deg,#1A0800,#E65C00)', color: 'white', padding: '1rem 1.5rem', textAlign: 'center' }}>
              <div style={{ fontFamily: "'Playfair Display',serif", fontWeight: 900, fontSize: '1.1rem' }}>Foodie Lover</div>
              <div style={{ fontSize: '0.72rem', opacity: 0.8 }}>Table {tableId} • {activeOrder.id}</div>
              <div style={{ fontSize: '0.7rem', opacity: 0.7 }}>{new Date(activeOrder.timestamp).toLocaleString('en-IN')}</div>
            </div>
            <div style={{ padding: '1rem 1.5rem' }}>
              {(activeOrder.items || []).map((item, i) => (
                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.35rem 0', borderBottom: '1px solid #f5f0e8', fontSize: '0.85rem' }}>
                  <span style={{ color: '#333' }}>{item.name} <span style={{ color: '#aaa', fontSize: '0.75rem' }}>×{item.qty}</span></span>
                  <span style={{ fontWeight: 700, color: '#1A0800' }}>₹{item.subtotal ?? item.price * item.qty}</span>
                </div>
              ))}
              <div style={{ paddingTop: '0.6rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', color: '#666', marginBottom: '0.25rem' }}>
                  <span>Subtotal</span><span>₹{activeOrder.subtotal}</span>
                </div>
                {(activeOrder.discount ?? 0) > 0 && (
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', color: '#16a34a', marginBottom: '0.25rem' }}>
                    <span>Discount</span><span>−₹{activeOrder.discount}</span>
                  </div>
                )}
                <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 900, fontSize: '1rem', color: '#E65C00', paddingTop: '0.4rem', borderTop: '2px solid #f5f0e8' }}>
                  <span>Total</span><span>₹{activeOrder.total}</span>
                </div>
              </div>
            </div>
            <div style={{ background: '#f9fafb', padding: '0.75rem 1.5rem', fontSize: '0.75rem', color: '#888', textAlign: 'center' }}>
              Customer: {activeOrder.customerName} • Payment: {activeOrder.payment === 'cod' ? 'Cash' : activeOrder.payment}
            </div>
          </div>

          {/* Order Again — resets all active order state */}
          <button
            onClick={() => {
              setActiveOrderId(null);
              setActiveOrder(null);
              setView('menu');
            }}
            style={{ width: '100%', padding: '0.85rem', background: '#E65C00', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 700, fontSize: '1rem', cursor: 'pointer', fontFamily: 'Poppins,sans-serif' }}
          >
            🍽️ Order Again
          </button>
        </div>
      </div>
    );
  }

  // ── MENU VIEW (default) ────────────────────────────────────────────────────
  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg,#faf8f3,#f5f0e8)', fontFamily: 'Poppins,sans-serif' }}>
      {/* Header */}
      <div style={{ background: 'linear-gradient(135deg,#1A0800,#2D0F00)', color: 'white', padding: '1rem 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, zIndex: 100 }}>
        <div>
          <div style={{ fontFamily: "'Playfair Display',serif", fontSize: '1.2rem', fontWeight: 900 }}>🍽️ Table {tableId}</div>
          <div style={{ fontSize: '0.72rem', color: '#F9A826' }}>Scan &amp; Order</div>
        </div>
        <div style={{ display: 'flex', gap: '0.6rem', alignItems: 'center' }}>
          <button
            onClick={() => callWaiter('Assistance needed')}
            disabled={callCooldown}
            style={{ background: callSent ? '#16a34a' : callCooldown ? '#4b5563' : '#F9A826', border: 'none', color: callCooldown && !callSent ? '#9ca3af' : '#1A0800', padding: '0.45rem 0.85rem', borderRadius: '20px', fontWeight: 700, cursor: callCooldown ? 'not-allowed' : 'pointer', fontSize: '0.72rem', fontFamily: 'Poppins,sans-serif' }}
          >
            {callSent ? '✅ Called!' : '🔔 Call Waiter'}
          </button>

          <button
            onClick={() => setCartOpen(true)}
            style={{ background: '#E65C00', border: 'none', color: 'white', padding: '0.45rem 1rem', borderRadius: '20px', fontWeight: 700, cursor: 'pointer', fontSize: '0.82rem', display: 'flex', alignItems: 'center', gap: '0.4rem', fontFamily: 'Poppins,sans-serif' }}
          >
            🛒
            {cartCount > 0 && (
              <span style={{ background: 'white', color: '#E65C00', borderRadius: '50%', width: '18px', height: '18px', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.7rem', fontWeight: 900 }}>
                {cartCount}
              </span>
            )}
          </button>
        </div>
      </div>

      {/* Active order tracker pill — fixed duplicate style attr */}
      {inProgressOrder && (
        <div
          onClick={() => {
            setActiveOrderId(inProgressOrder.id);
            setActiveOrder(inProgressOrder);
            setView('tracking');
          }}
          style={{ cursor: 'pointer', background: '#fff7ed', borderBottom: '2px solid #fed7aa', padding: '0.65rem 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
        >
          <div>
            <div style={{ fontSize: '0.82rem', fontWeight: 700, color: '#92400e' }}>📋 Order in Progress</div>
            <div style={{ fontSize: '0.7rem', color: '#b45309' }}>
              {STATUS_LABEL[inProgressOrder.status]?.label} — {inProgressOrder.id}
            </div>
          </div>
          <span style={{ fontSize: '0.75rem', color: '#E65C00', fontWeight: 700 }}>Track →</span>
        </div>
      )}

      {/* Category filters */}
      <div style={{ padding: '0.75rem 1rem', display: 'flex', gap: '0.4rem', overflowX: 'auto' }}>
        {CATEGORIES.map(cat => (
          <button key={cat} onClick={() => setFilter(cat)} style={{ padding: '0.35rem 0.85rem', borderRadius: '20px', border: `2px solid ${filter === cat ? '#E65C00' : '#ddd'}`, background: filter === cat ? '#E65C00' : 'white', color: filter === cat ? 'white' : '#666', fontWeight: 600, cursor: 'pointer', whiteSpace: 'nowrap', fontSize: '0.78rem', fontFamily: 'Poppins,sans-serif' }}>
            {cat}
          </button>
        ))}
      </div>

      {/* Menu grid */}
      <div style={{ padding: '0 1rem 5rem', display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(260px,1fr))', gap: '0.85rem' }}>
        {filtered.map(item => {
          const inCart = cart.find(c => c.item.id === item.id);
          const atMax  = inCart && inCart.qty >= MAX_QTY;
          return (
            <div key={item.id} style={{ background: 'white', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.08)' }}>
              {item.img && <img src={item.img} alt={item.name} style={{ width: '100%', height: '140px', objectFit: 'cover' }} />}
              <div style={{ padding: '0.85rem' }}>
                <div style={{ fontWeight: 700, fontSize: '0.9rem', color: '#1A0800', marginBottom: '0.2rem' }}>{item.name}</div>
                {item.badge && (
                  <span style={{ fontSize: '0.62rem', background: '#FFF5EB', color: '#E65C00', padding: '0.1rem 0.35rem', borderRadius: '6px', fontWeight: 700 }}>
                    {BADGE_LABELS[item.badge] || item.badge}
                  </span>
                )}
                <div style={{ fontSize: '0.74rem', color: '#888', margin: '0.3rem 0 0.6rem', lineHeight: '1.3' }}>{item.desc}</div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span style={{ fontWeight: 900, color: '#E65C00' }}>₹{item.price}</span>
                  {inCart ? (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                      <button onClick={() => changeQty(item.id, -1)} style={{ width: '26px', height: '26px', borderRadius: '50%', border: '2px solid #E65C00', background: 'white', color: '#E65C00', fontWeight: 900, cursor: 'pointer', fontSize: '0.9rem' }}>−</button>
                      <span style={{ fontWeight: 800, minWidth: '18px', textAlign: 'center' }}>{inCart.qty}</span>
                      <button
                        onClick={() => changeQty(item.id, 1)}
                        disabled={!!atMax}
                        style={{ width: '26px', height: '26px', borderRadius: '50%', background: atMax ? '#ddd' : '#E65C00', border: 'none', color: 'white', fontWeight: 900, cursor: atMax ? 'not-allowed' : 'pointer', fontSize: '0.9rem' }}
                      >+</button>
                    </div>
                  ) : (
                    <button onClick={() => addToCart(item)} style={{ background: '#E65C00', color: 'white', border: 'none', padding: '0.35rem 0.85rem', borderRadius: '20px', fontWeight: 700, cursor: 'pointer', fontSize: '0.78rem', fontFamily: 'Poppins,sans-serif' }}>+ Add</button>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Cart drawer */}
      {cartOpen && (
        <div className="modal-overlay show" onClick={() => { if (!isSubmitting) setCartOpen(false); }}>
          <div onClick={e => e.stopPropagation()} style={{ background: 'white', borderRadius: '16px', width: '100%', maxWidth: '420px', maxHeight: '88vh', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
            <div style={{ background: 'linear-gradient(135deg,#1A0800,#E65C00)', color: 'white', padding: '1rem 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontFamily: "'Playfair Display',serif", fontWeight: 900 }}>🛒 Cart — Table {tableId}</span>
              <button onClick={() => setCartOpen(false)} style={{ background: 'none', border: 'none', color: 'white', fontSize: '1.4rem', cursor: 'pointer' }}>×</button>
            </div>
            <div style={{ flex: 1, overflowY: 'auto', padding: '1rem 1.5rem' }}>
              {!cart.length
                ? <p style={{ color: '#999', textAlign: 'center', padding: '2rem 0' }}>Cart is empty</p>
                : cart.map(c => (
                  <div key={c.item.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.6rem 0', borderBottom: '1px solid #f5f0e8' }}>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: '0.88rem' }}>{c.item.name}</div>
                      <div style={{ fontSize: '0.75rem', color: '#888' }}>₹{c.item.price} × {c.qty}</div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                      <button onClick={() => changeQty(c.item.id, -1)} style={{ width: '24px', height: '24px', borderRadius: '50%', border: '2px solid #E65C00', background: 'white', color: '#E65C00', fontWeight: 900, cursor: 'pointer' }}>−</button>
                      <span style={{ fontWeight: 800, minWidth: '16px', textAlign: 'center' }}>{c.qty}</span>
                      <button onClick={() => changeQty(c.item.id, 1)} disabled={c.qty >= MAX_QTY} style={{ width: '24px', height: '24px', borderRadius: '50%', background: c.qty >= MAX_QTY ? '#ddd' : '#E65C00', border: 'none', color: 'white', fontWeight: 900, cursor: c.qty >= MAX_QTY ? 'not-allowed' : 'pointer' }}>+</button>
                    </div>
                  </div>
                ))
              }
            </div>
            {cart.length > 0 && (
              <div style={{ padding: '1rem 1.5rem', borderTop: '2px solid #f5f0e8' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 900, fontSize: '1rem', marginBottom: '0.75rem', color: '#1A0800' }}>
                  <span>Total</span><span style={{ color: '#E65C00' }}>₹{cartTotal}</span>
                </div>
                <button onClick={() => { setCartOpen(false); setShowCheckout(true); }} style={{ width: '100%', background: '#E65C00', color: 'white', border: 'none', padding: '0.7rem', borderRadius: '10px', fontWeight: 700, fontSize: '0.95rem', cursor: 'pointer', fontFamily: 'Poppins,sans-serif' }}>
                  Place Order →
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Name prompt / checkout */}
      {showCheckout && (
        <div className="modal-overlay show" onClick={() => { if (!isSubmitting) setShowCheckout(false); }}>
          <div onClick={e => e.stopPropagation()} style={{ background: 'white', borderRadius: '16px', width: '100%', maxWidth: '380px', padding: '2rem' }}>
            <h3 style={{ fontFamily: "'Playfair Display',serif", marginBottom: '0.5rem', color: '#1A0800' }}>Your Name</h3>
            <p style={{ fontSize: '0.78rem', color: '#888', marginBottom: '1rem' }}>We&apos;ll use this to track your order status.</p>
            <input
              value={name}
              onChange={e => setName(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && !isSubmitting && placeOrder()}
              placeholder="Enter your name"
              disabled={isSubmitting}
              style={{ ...inp, marginBottom: '1rem' }}
              autoFocus
            />
            {/* Order summary */}
            <div style={{ background: '#FFF5EB', borderRadius: '8px', padding: '0.6rem 0.85rem', marginBottom: '1rem', fontSize: '0.82rem' }}>
              {cart.map(c => (
                <div key={c.item.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.15rem 0' }}>
                  <span>{c.item.name} × {c.qty}</span>
                  <span>₹{c.item.price * c.qty}</span>
                </div>
              ))}
              <div style={{ borderTop: '1px solid #E65C00', marginTop: '0.4rem', paddingTop: '0.4rem', fontWeight: 800, color: '#E65C00', display: 'flex', justifyContent: 'space-between' }}>
                <span>Total</span><span>₹{cartTotal}</span>
              </div>
            </div>
            <button
              onClick={placeOrder}
              disabled={isSubmitting}
              style={{ width: '100%', background: isSubmitting ? '#bbb' : '#E65C00', color: 'white', border: 'none', padding: '0.75rem', borderRadius: '10px', fontWeight: 700, fontSize: '1rem', cursor: isSubmitting ? 'not-allowed' : 'pointer', fontFamily: 'Poppins,sans-serif', transition: 'background 0.2s' }}
            >
              {isSubmitting ? '⏳ Placing Order...' : '✅ Confirm Order'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default function TablePage() {
  return (
    <Suspense fallback={
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', fontFamily: 'Poppins,sans-serif', color: '#E65C00', fontSize: '1.1rem' }}>
        Loading menu...
      </div>
    }>
      <TableContent />
    </Suspense>
  );
}
